import sys

class Solution:
    def solve(self, s1: str, s2: str) -> str:
        # Anagrams must have same length
        if len(s1) != len(s2):
            return "NO"
        # Count characters using dictionary
        freq = {}
        for ch in s1:
            freq[ch] = freq.get(ch, 0) + 1
        for ch in s2:
            if ch not in freq:
                return "NO"
            freq[ch] -= 1
            if freq[ch] == 0:
                del freq[ch]
        return "YES" if not freq else "NO"

if __name__ == "__main__":
    it = iter(sys.stdin.read().split())
    try:
        _ = int(next(it))  # length of first string, can be ignored
        s1 = next(it)
        _ = int(next(it))  # length of second string
        s2 = next(it)
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.solve(s1, s2)
    print(ans)

