#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string solve(string& s1, string& s2) {
        if (s1.size() != s2.size()) return "NO";
        array<int, 256> cnt{}; // assuming ASCII
        for (char c : s1) cnt[(unsigned char)c]++;
        for (char c : s2) {
            if (cnt[(unsigned char)c] == 0) return "NO";
            cnt[(unsigned char)c]--;
        }
        return "YES";
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n1, n2;
    if (!(cin >> n1)) return 0;
    string s1; s1.reserve(n1);
    cin >> s1;
    if (!(cin >> n2)) return 0;
    string s2; s2.reserve(n2);
    cin >> s2;
    Solution sol;
    string ans = sol.solve(s1, s2);
    cout << ans << "\n";
    return 0;
}
